class Solution {
public:
    int solve(string s, string t, int k) {
        int n = s.size();
        int maxLen = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                string temp = s.substr(i, j - i + 1);
                int count = 0;
                for (int z = 0; z < j - i + 1; z++) {
                    if (temp[z] != t[z]) {
                        count++;
                    }
                }
                if (count <= k && j - i + 1 > maxLen) {
                    maxLen = j - i + 1;
                }
            }
        }
        return maxLen;
    }
};

